#[derive(Clone, Debug, PartialEq, Eq)]
pub enum Error {
    AlignmentMismatch { dst_type: &'static str, dst_minimum_alignment: usize },
    LengthMismatch { dst_type: &'static str, src_slice_size: usize, dst_type_size: usize },
}

pub unsafe trait FromByteSlice where Self: Sized {
    fn from_byte_slice<T: AsRef<[u8]> + ?Sized>(slice: &T) -> Result<&[Self], Error>;
    fn from_mut_byte_slice<T: AsMut<[u8]> + ?Sized>(slice: &mut T) -> Result<&mut [Self], Error>;
}

pub trait AsSliceOf {
    fn as_slice_of<T: FromByteSlice>(&self) -> Result<&[T], Error>;
}

impl<U: AsRef<[u8]> + ?Sized> AsSliceOf for U {
    #[inline]
    fn as_slice_of<T: FromByteSlice>(&self) -> Result<&[T], Error> {
        FromByteSlice::from_byte_slice(self)
    }
}

pub trait TypeName {
    const TYPE_NAME: &'static str;
}

fn check_alignment<T, U>(data: &T) -> Result<usize, Error>
where
    U: TypeName,
    T: AsRef<[u8]> + ?Sized,
{
    let alignment = core::mem::align_of::<U>();
    if (data.as_ref().as_ptr() as usize) % alignment != 0 {
        Err(Error::AlignmentMismatch { dst_type: U::TYPE_NAME, dst_minimum_alignment: alignment })
    } else {
        Ok(alignment)
    }
}

fn check_length<T, U>(data: &T) -> Result<usize, Error>
where
    U: TypeName,
    T: AsRef<[u8]> + ?Sized,
{
    let size_out = core::mem::size_of::<U>();
    if data.as_ref().len() % size_out != 0 {
        Err(Error::LengthMismatch { dst_type: U::TYPE_NAME, src_slice_size: data.as_ref().len(), dst_type_size: size_out })
    } else {
        Ok(size_out)
    }
}

fn check_constraints<U>(data: &[u8]) -> Result<usize, Error>
where
    U: TypeName,
{
    if data.is_empty() {
        return Ok(0);
    }
    check_alignment::<[u8], U>(data)?;
    let size_out = check_length::<[u8], U>(data)?;
    Ok(data.len() / size_out)
}

macro_rules! impl_trait {
    ($to:ty) => {
        impl TypeName for $to {
            const TYPE_NAME: &'static str = stringify!($to);
        }
        unsafe impl FromByteSlice for $to {
            #[inline]
            fn from_byte_slice<T: AsRef<[u8]> + ?Sized>(slice: &T) -> Result<&[$to], Error> {
                let slice = slice.as_ref();
                let len = check_constraints::<$to>(slice)?;
                if len == 0 {
                    Ok(&[])
                } else {
                    unsafe { Ok(core::slice::from_raw_parts(slice.as_ptr() as *const $to, len)) }
                }
            }
            #[inline]
            fn from_mut_byte_slice<T: AsMut<[u8]> + ?Sized>(slice: &mut T) -> Result<&mut [$to], Error> {
                let slice = slice.as_mut();
                let len = check_constraints::<$to>(slice)?;
                if len == 0 {
                    Ok(&mut [])
                } else {
                    unsafe { Ok(core::slice::from_raw_parts_mut(slice.as_mut_ptr() as *mut $to, len)) }
                }
            }
        }
    };
}

