#[derive(Default, Copy, Clone)]
#[repr(transparent)]
pub struct Scalar([u8; 32]);

impl Scalar {
    fn num_bits(&self) -> usize {
        let mut i = 32usize;
        while i > 0 {
            i -= 1;
            if self.0[i] != 0 {
                return (i + 1) * 8 - self.0[i].leading_zeros() as usize;
            }
        }
        0usize
    }
}

