use std::process::Command;

pub trait Execute {
    fn execute(&mut self) -> Result<Option<i32>, std::io::Error>;
    fn execute_output(&mut self) -> Result<std::process::Output, std::io::Error>;
}

impl Execute for Command {
    fn execute(&mut self) -> Result<Option<i32>, std::io::Error> {
        self.stdout(std::process::Stdio::null());
        self.stderr(std::process::Stdio::null());
        Ok(self.status()?.code())
