use regex::Regex;

#[derive(Debug, Clone, PartialEq)]
pub enum InvalidRelease {
    TooLong,
    RestrictedName,
    BadCharacters,
}

lazy_static! {
    static ref VALID_API_ATTRIBUTE_REGEX: Regex = Regex::new(r"^[^\\/\r\n]*$").unwrap();
    static ref HEX_REGEX: Regex = Regex::new(r"^[a-fA-F0-9]+$").unwrap();
}

pub fn validate_release(release: &str) -> Result<(), InvalidRelease> {
    if release.len() > 200 {
        Err(InvalidRelease::TooLong)
    } else if release == "." || release == ".." || release.eq_ignore_ascii_case("latest") {
        Err(InvalidRelease::RestrictedName)
    } else if !VALID_API_ATTRIBUTE_REGEX.is_match(release) {
        Err(InvalidRelease::BadCharacters)
    } else {
        Ok(())
    }
}

pub struct Release<'a> {
    raw: &'a str,
    package: &'a str,
    version_raw: &'a str,
    version: Option<Version<'a>>,
}

pub struct Version<'a> {
    raw: &'a str,
    major: &'a str,
    minor: &'a str,
    patch: &'a str,
    revision: &'a str,
    pre: &'a str,
    before_code: &'a str,
    build_code: &'a str,
    components: u8,
}

impl<'a> Release<'a> {
    pub fn parse(release: &'a str) -> Result<Release<'a>, InvalidRelease> {
        let release = release.trim();
        validate_release(release)?;
        if let Some(caps) = RELEASE_REGEX.captures(release) {
            let package = caps.get(1).unwrap().as_str();
            let version_raw = caps.get(2).unwrap().as_str();
            let version = if !is_build_hash(version_raw) {
                Version::parse(version_raw).ok()
            } else {
                None
            };
            Ok(Release { raw: release, package, version_raw, version })
        } else {
            Ok(Release { raw: release, package: "", version_raw: release, version: None })
        }
    }

    pub fn package(&self) -> Option<&'a str> {
        if self.package.is_empty() { None } else { Some(self.package) }
    }

    pub fn version(&self) -> Option<&Version<'a>> { self.version.as_ref() }

    pub fn build_hash(&self) -> Option<&'a str> {
        self.version
            .as_ref()
            .and_then(|v| v.build_code())
            .filter(|s| is_build_hash(s))
            .or_else(|| if is_build_hash(self.version_raw) { Some(self.version_raw) } else { None })
    }
}

impl<'a> Version<'a> {
    pub fn parse(version: &'a str) -> Result<Version<'a>, ()> { unimplemented!() }
    pub fn major(&self) -> u64 { self.major.parse().unwrap_or_default() }
    pub fn minor(&self) -> u64 { self.minor.parse().unwrap_or_default() }
    pub fn patch(&self) -> u64 { self.patch.parse().unwrap_or_default() }
