pub trait BitSet {
    fn bit_len(&self) -> usize;
    fn bit_init(&mut self, value: bool) -> &mut Self;
    fn bit_test(&self, bit: usize) -> bool;
    fn bit_set(&mut self, bit: usize) -> &mut Self;
    fn bit_reset(&mut self, bit: usize) -> &mut Self;
    fn bit_flip(&mut self, bit: usize) -> &mut Self;
    fn bit_cond(&mut self, bit: usize, value: bool) -> &mut Self;
    fn bit_all(&self) -> bool;
    fn bit_any(&self) -> bool;
    fn bit_eq(&self, rhs: &Self) -> bool;
    fn bit_disjoint(&self, rhs: &Self) -> bool;
    fn bit_subset(&self, rhs: &Self) -> bool;
    fn bit_superset(&self, rhs: &Self) -> bool;
    fn bit_or(&mut self, rhs: &Self) -> &mut Self;
    fn bit_and(&mut self, rhs: &Self) -> &mut Self;
    fn bit_andnot(&mut self, rhs: &Self) -> &mut Self;
    fn bit_xor(&mut self, rhs: &Self) -> &mut Self;
    fn bit_not(&mut self) -> &mut Self;
    fn bit_mask(&mut self, rhs: &Self, mask: &Self) -> &mut Self;
    fn bit_count(&self) -> usize;
}

impl BitSet for [u32] {
    #[inline]
    fn bit_len(&self) -> usize { self.len() * 32 }
    #[inline]
    fn bit_init(&mut self, value: bool) -> &mut Self {
        let value = <u32>::wrapping_add(!(value as u32), 1);
        for i in 0..self.len() { self[i] = value; }
        self
    }
    #[inline]
    fn bit_test(&self, bit: usize) -> bool { self[bit / 32] & (1 << (bit % 32)) != 0 }
    #[inline]
    fn bit_set(&mut self, bit: usize) -> &mut Self { self[bit / 32] |= 1 << (bit % 32); self }
    #[inline]
    fn bit_reset(&mut self, bit: usize) -> &mut Self { self[bit / 32] &= !(1 << (bit % 32)); self }
    #[inline]
    fn bit_flip(&mut self, bit: usize) -> &mut Self { self[bit / 32] ^= 1 << (bit % 32); self }
    #[inline]
    fn bit_cond(&mut self, bit: usize, value: bool) -> &mut Self {
        let index = bit / 32;
        let mask = 1 << (bit % 32);
        self[index] = (self[index] & !mask) | (<u32>::wrapping_add(!(value as u32), 1) & mask);
        self
    }
    #[inline]
    fn bit_all(&self) -> bool { self.iter().all(|&x| x == !0) }
    #[inline]
    fn bit_any(&self) -> bool { self.iter().any(|&x| x != 0) }
    #[inline]
    fn bit_eq(&self, rhs: &Self) -> bool { self == rhs }
    #[inline]
    fn bit_disjoint(&self, rhs: &Self) -> bool { self.iter().zip(rhs).all(|(&a,&b)| a & b == 0) }
    #[inline]
    fn bit_subset(&self, rhs: &Self) -> bool { self.iter().zip(rhs).all(|(&a,&b)| a | b == b) }
    #[inline]
    fn bit_superset(&self, rhs: &Self) -> bool { rhs.bit_subset(self) }
    #[inline]
    fn bit_or(&mut self, rhs: &Self) -> &mut Self { for i in 0..self.len() { self[i] |= rhs[i]; } self }
    #[inline]
    fn bit_and(&mut self, rhs: &Self) -> &mut Self { for i in 0..self.len() { self[i] &= rhs[i]; } self }
    #[inline]
    fn bit_andnot(&mut self, rhs: &Self) -> &mut Self { for i in 0..self.len() { self[i] &= !rhs[i]; } self }
    #[inline]
    fn bit_xor(&mut self, rhs: &Self) -> &mut Self { for i in 0..self.len() { self[i] ^= rhs[i]; } self }
    #[inline]
    fn bit_not(&mut self) -> &mut Self { for i in 0..self.len() { self[i] = !self[i]; } self }
    #[inline]
    fn bit_mask(&mut self, rhs: &Self, mask: &Self) -> &mut Self {
        for i in 0..self.len() { self[i] = self[i] & !mask[i] | rhs[i] & mask[i]; }
        self
    }
    #[inline]
    fn bit_count(&self) -> usize { self.iter().map(|&x| x.count_ones() as usize).sum() }
}

pub struct Matrix4x4 {
    pub M11: f32, pub M12: f32, pub M13: f32, pub M14: f32,
    pub M21: f32, pub M22: f32, pub M23: f32, pub M24: f32,
    pub M31: f32, pub M32: f32, pub M33: f32, pub M34: f32,
    pub M41: f32, pub M42: f32, pub M43: f32, pub M44: f32,
}
impl Matrix4x4 {
    pub const fn translation(x: f32, y: f32, z: f32) -> Self {
        Self { M11: 1.0, M12: 0.0, M13: 0.0, M14: 0.0,
               M21: 0.0, M22: 1.0, M23: 0.0, M24: 0.0,
               M31: 0.0, M32: 0.0, M33: 1.0, M34: 0.0,
               M41: x,   M42: y,   M43: z,   M44: 1.0 }
    }
    pub fn rotation_y(degree: f32) -> Self {
        windows_link::link!("d2d1.dll" "system" fn D2D1SinCos(angle: f32, sin: *mut f32, cos: *mut f32));
        let angle = degree * (3.141592654 / 180.0);
        let mut sin = 0.0; let mut cos = 0.0;
        unsafe { D2D1SinCos(angle, &mut sin, &mut cos); }
        Self { M11: cos, M12: 0.0, M13: -sin, M14: 0.0,
               M21: 0.0, M22: 1.0, M23: 0.0,  M24: 0.0,
               M31: sin, M32: 0.0, M33: cos,  M34: 0.0,
               M41: 0.0, M42: 0.0, M43: 0.0,  M44: 1.0 }
    }
    fn impl_mul(&self, rhs: &Self) -> Self {
        Self {
            M11: self.M11 * rhs.M11 + self.M12 * rhs.M21 + self.M13 * rhs.M31 + self.M14 * rhs.M41,
            M12: self.M11 * rhs.M12 + self.M12 * rhs.M22 + self.M13 * rhs.M32 + self.M14 * rhs.M42,
            M13: self.M11 * rhs.M13 + self.M12 * rhs.M23 + self.M13 * rhs.M33 + self.M14 * rhs.M43,
            M14: self.M11 * rhs.M14 + self.M12 * rhs.M24 + self.M13 * rhs.M34 + self.M14 * rhs.M44,
            M21: self.M21 * rhs.M11 + self.M22 * rhs.M21 + self.M23 * rhs.M31 + self.M24 * rhs.M41,
            M22: self.M21 * rhs.M12 + self.M22 * rhs.M22 + self.M23 * rhs.M32 + self.M24 * rhs.M42,
            M23: self.M21 * rhs.M13 + self.M22 * rhs.M23 + self.M23 * rhs.M33 + self.M24 * rhs.M43,
            M24: self.M21 * rhs.M14 + self.M22 * rhs.M24 + self.M23 * rhs.M34 + self.M24 * rhs.M44,
            M31: self.M31 * rhs.M11 + self.M32 * rhs.M21 + self.M33 * rhs.M31 + self.M34 * rhs.M41,
            M32: self.M31 * rhs.M12 + self.M32 * rhs.M22 + self.M33 * rhs.M32 + self.M34 * rhs.M42,
            M33: self.M31 * rhs.M13 + self.M32 * rhs.M23 + self.M33 * rhs.M33 + self.M34 * rhs.M43,
            M34: self.M31 * rhs.M14 + self.M32 * rhs.M24 + self.M33 * rhs.M34 + self.M34 * rhs.M44,
            M41: self.M41 * rhs.M11 + self.M42 * rhs.M21 + self.M43 * rhs.M31 + self.M44 * rhs.M41,
            M42: self.M41 * rhs.M12 + self.M42 * rhs.M22 + self.M43 * rhs.M32 + self.M44 * rhs.M42,
            M43: self.M41 * rhs.M13 + self.M42 * rhs.M23 + self.M43 * rhs.M33 + self.M44 * rhs.M43,
            M44: self.M41 * rhs.M14 + self.M42 * rhs.M24 + self.M43 * rhs.M34 + self.M44 * rhs.M44,
        }
    }
}
impl core::ops::Mul<Matrix4x4> for Matrix4x4 {
    type Output = Matrix4x4;
    fn mul(self, rhs: Matrix4x4) -> Matrix4x4 { self.impl_mul(&rhs) }
}

