}

impl SqlFragment for PrimaryKey {
    fn create(&self) -> String {
        let cols = self.column_names.join(", ");
        match self.db_type {
            DbType::Postgres => {
                format!(
                    "ALTER TABLE {}.{} ADD CONSTRAINT {} PRIMARY KEY ({});",
                    self.namespace,
                    self.table_name,
                    self.sql_name(),
                    cols
                )
            }
        }
    }
}

