pub struct Join<C, S> {
    collection: C,
    sep: S,
}

impl<C, S: core::fmt::Display> core::fmt::Display for Join<C, S>
where
    for<'a> &'a C: core::iter::IntoIterator,
    for<'a> <&'a C as core::iter::IntoIterator>::Item: core::fmt::Display,
{
    fn fmt(&self, f: &mut core::fmt::Formatter) -> core::fmt::Result {
        let mut iter = self.collection.into_iter();
        match iter.next() {
            None => Ok(()),
            Some(first) => {
                first.fmt(f)?;
                iter.try_for_each(move |element| {
                    self.sep.fmt(f)?;
                    element.fmt(f)
                })
            }
        }
    }
}

pub trait Joinable: Sized {
    type Collection;
    fn join_with<S>(self, sep: S) -> Join<Self::Collection, S>;
}

impl<T> Joinable for T
where
    for<'a> &'a T: core::iter::IntoIterator,
{
    type Collection = Self;
    fn join_with<S>(self, sep: S) -> Join<Self, S> {
        Join { collection: self, sep }
    }
}

