use std::borrow::Borrow;
use std::cmp::Ordering;

pub trait SliceExt<T> {
    fn eytzinger_search<Q: ?Sized>(&self, x: &Q) -> Option<usize>
    where
        Q: Ord,
        T: Borrow<Q>;
    fn eytzinger_search_by<'a, F>(&'a self, f: F) -> Option<usize>
    where
        F: FnMut(&'a T) -> Ordering,
        T: 'a;
}

impl<T> SliceExt<T> for [T] {
    #[inline]
    fn eytzinger_search<Q: ?Sized>(&self, x: &Q) -> Option<usize>
    where
        Q: Ord,
        T: Borrow<Q>,
    {
        self.eytzinger_search_by(|e| e.borrow().cmp(x))
    }

    #[inline]
    fn eytzinger_search_by<'a, F>(&'a self, mut f: F) -> Option<usize>
    where
        F: FnMut(&'a T) -> Ordering,
        T: 'a,
    {
        let mut i = 0;
        loop {
            match self.get(i) {
                Some(v) => match f(v) {
                    Ordering::Equal => return Some(i),
                    o => {
                        let o = (o as usize >> 1) & 1;
                        i = 2 * i + 1 + o;
                    }
                },
                None => return None,
            }
        }
    }
}

