    T: PartialEq + std::fmt::Display,
{
    pub fn is_some_with_value(&self, value: T) {
        match &self.value {
            Some(val) => {
                if *val != value {
                    panic!(
                        "Expected '{}' to be Some({}), but found Some({}).",
                        self.name,
                        value,
                        val
                    );
                }
            }
            None => panic!(
                "Expected '{}' to be Some({}), but found None.",
                self.name,
                value
            ),
        }
    }
}

