pub struct ByteBufferMut { data: Vec<u8> }

impl ByteBufferMut {
    pub fn new() -> ByteBufferMut { ByteBufferMut { data: vec![] } }
    pub fn write_var_float(&mut self, value: f32) {
        let mut bits = value.to_bits();
        bits = (bits >> 23) | (bits << 9);
        if (bits & 255) == 0 {
            self.data.push(0);
            return;
        }
        self.data.extend_from_slice(&[
            bits as u8,
            (bits >> 8) as u8,
            (bits >> 16) as u8,
            (bits >> 24) as u8,
        ]);
    }
}

pub struct BitVector {
    vector: Vec<u64>,
}

impl BitVector {
    pub fn new(bits: usize) -> Self {
        BitVector {
            vector: vec![0; (bits + 63) / 64],
        }
    }

    pub fn insert(&mut self, bit: usize) -> bool {
        if bit >= self.capacity() {
            self.grow(bit + 1);
        }
        let (word, mask) = word_mask(bit);
        let data = &mut self.vector[word];
        let value = *data;
        let new_value = value | mask;
        *data = new_value;
        new_value != value
    }

    fn capacity(&self) -> usize {
        self.vector.len() * std::mem::size_of::<u64>() * 8
    }

    fn grow(&mut self, num_bits: usize) {
        let num_words = (num_bits + 63) / 64;
        if self.vector.len() < num_words {
            self.vector.resize(num_words, 0);
        }
    }
}

fn word_mask(index: usize) -> (usize, u64) {
    let word = index / 64;
    let mask = 1 << (index % 64);
    (word, mask)
}

