pub trait SliceExtention {
    fn lift(&mut self, from: usize, to: usize);
}

impl<T: PartialOrd> SliceExtention for [T] {
    fn lift(&mut self, from: usize, to: usize) {
        if from >= self.len() || to >= self.len() || from == to {
            return;
        }
        if from < to {
            for i in from..to {
                self.swap(i, i + 1);
            }
        } else {
            for i in (to..from).rev() {
                self.swap(i + 1, i);
            }
        }
    }
}

