pub struct Rgb {
    pub r: u8,
    pub g: u8,
    pub b: u8,
}

impl Rgb {
    #[must_use]
    pub fn as_hex(&self) -> Hex {
        let Rgb { r, g, b } = self;
        Hex(format!("{r:02X}{g:02X}{b:02X}"))
    }
}

pub struct Hex(String);

impl Hex {
    fn as_rgb(&self) -> Rgb {
        let s = self.0.as_str();
        let r = u8::from_str_radix(&s[..2], 16).unwrap();
        let g = u8::from_str_radix(&s[2..4], 16).unwrap();
        let b = u8::from_str_radix(&s[4..6], 16).unwrap();
        Rgb { r, g, b }
    }
}

use std::cell::{Ref, RefCell, RefMut};
use std::fmt;
use std::rc::{Rc, Weak};

type Link<T> = Rc<RefCell<NodeData<T>>>;
type WeakLink<T> = Weak<RefCell<NodeData<T>>>;

pub struct Node<T>(Link<T>);

struct NodeData<T> {
    parent: Option<WeakLink<T>>, 
    first_child: Option<Link<T>>, 
    last_child: Option<WeakLink<T>>, 
    previous_sibling: Option<WeakLink<T>>, 
    next_sibling: Option<Link<T>>, 
    data: T,
}

impl<T> Node<T> {
    pub fn new(data: T) -> Node<T> {
        Node(Rc::new(RefCell::new(NodeData {
            parent: None,
            first_child: None,
            last_child: None,
            previous_sibling: None,
            next_sibling: None,
            data,
        })))
    }

    pub fn borrow(&self) -> Ref<T> {
        Ref::map(self.0.borrow(), |v| &v.data)
    }
}

