pub trait Microtype {
    type Inner;
    fn new(inner: Self::Inner) -> Self;
    fn into_inner(self) -> Self::Inner;
    fn inner(&self) -> &Self::Inner;
    fn inner_mut(&mut self) -> &mut Self::Inner;
    fn convert<T: Microtype<Inner = Self::Inner>>(self) -> T;
}

#[repr(transparent)]
pub struct Email(pub String);

impl ::microtype::Microtype for Email {
    type Inner = String;
    fn new(inner: Self::Inner) -> Self {
        Self(inner)
    }
    fn into_inner(self) -> Self::Inner {
        self.0
    }
    fn inner(&self) -> &Self::Inner {
        &self.0
    }
    fn inner_mut(&mut self) -> &mut Self::Inner {
        &mut self.0
    }
    fn convert<T: ::microtype::Microtype<Inner = Self::Inner>>(self) -> T {
        T::new(self.0)
    }
}

impl ::std::convert::From<&str> for Email {
    fn from(s: &str) -> Self {
        Self(s.to_string())
    }
}

