        <String as ::std::fmt::Debug>::fmt(&self.0, f)
    }
}

impl ::std::clone::Clone for Email {
    fn clone(&self) -> Self {
        Self(self.0.clone())
    }
}

impl ::std::cmp::PartialEq for Email {
    fn eq(&self, other: &Self) -> bool {
        self.0.eq(&other.0)
    }
}

impl ::std::ops::Deref for Email {
    type Target = String;
    fn deref(&self) -> &Self::Target {
        &self.0
    }
}

impl ::std::ops::DerefMut for Email {
    fn deref_mut(&mut self) -> &mut Self::Target {
        &mut self.0
    }
}

impl ::std::str::FromStr for Email {
    type Err = ::core::convert::Infallible;
    fn from_str(s: &::core::primitive::str) -> Result<Self, Self::Err> {
        Ok(Self(s.to_string()))
    }
