pub struct Value {
    pub ty: u8,
    pub mh: u8,
    pub ml: u8,
    pub sh: u8,
    pub sl: u8,
}

impl Value {
    pub fn from_value(v: u16) -> Self {
        Value {
            sh: (v >> 8) as u8,
            sl: v as u8,
            ..Default::default()
        }
    }

    pub fn value(&self) -> u16 {
        ((self.sh as u16) << 8) | self.sl as u16
    }
}

