pub struct CachedOrdering<T: num_traits::Float + num_traits::FromPrimitive> {
    data: Vec<T>,
    in_order: std::collections::BTreeSet<usize>,
}
impl<T: num_traits::Float + num_traits::FromPrimitive> CachedOrdering<T> {
    fn new() -> Self {
        CachedOrdering { data: Vec::new(), in_order: std::collections::BTreeSet::new() }
    }
    fn add(&mut self, val: T) {
        self.data.push(val);
        self.in_order.clear();
    }
}

pub struct Percentiles<T: num_traits::Float + num_traits::FromPrimitive> {
    data: RefCell<CachedOrdering<T>>,
    nan_count: usize,
}
impl<T: num_traits::Float + num_traits::FromPrimitive> Percentiles<T> {
    pub fn new() -> Self {
        Percentiles { data: RefCell::new(CachedOrdering::new()), nan_count: 0 }
    }
    pub fn add(&mut self, rval: impl DerefCopy<Output = T>) {
        let val = rval.deref_copy();
        if val.is_nan() {
            self.nan_count += 1;
        } else {
            self.data.borrow_mut().add(val);
        }
    }
}

use std::collections::HashMap;
use std::hash::{Hash, Hasher};
use inc_stats::DerefCopy;

pub trait ToBytes {
    type Bytes: std::fmt::Debug + AsRef<[u8]> + AsMut<[u8]> + PartialEq + Eq + PartialOrd + Ord + std::hash::Hash + std::borrow::Borrow<[u8]> + std::borrow::BorrowMut<[u8]> + Default;
    fn to_bytes(&self) -> Self::Bytes;
}
impl ToBytes for f32 {
    type Bytes = [u8; 4];
    fn to_bytes(&self) -> Self::Bytes { self.to_ne_bytes() }
}
impl ToBytes for f64 {
    type Bytes = [u8; 8];
    fn to_bytes(&self) -> Self::Bytes { self.to_ne_bytes() }
}

pub struct HashFloat<T: num_traits::Float + ToBytes>(T);
impl<T: num_traits::Float + ToBytes> PartialEq for HashFloat<T> {
    fn eq(&self, other: &Self) -> bool { self.0 == other.0 }
}
impl<T: num_traits::Float + ToBytes> Eq for HashFloat<T> {}
impl<T: num_traits::Float + ToBytes> Hash for HashFloat<T> {
    fn hash<H: Hasher>(&self, state: &mut H) {
        self.0.to_bytes().hash(state);
    }
}

pub struct Mode<T: num_traits::Float + ToBytes> {
    counts: HashMap<HashFloat<T>, usize>,
    count: usize,
    nan_count: usize,
    mode: Vec<T>,
    mode_count: usize,
}
impl<T: num_traits::Float + ToBytes> Mode<T> {
    pub fn new() -> Self {
        Mode {
            counts: HashMap::new(),
            count: 0,
            nan_count: 0,
            mode: Vec::new(),
            mode_count: 0,
        }
    }
    pub fn add(&mut self, rval: impl DerefCopy<Output = T>) {
        let val = rval.deref_copy();
        self.count += 1;
        if val.is_nan() {
            self.nan_count += 1;
        } else {
            let entry = self.counts.entry(HashFloat(val)).or_insert(0);
            *entry += 1;
            if *entry > self.mode_count {
                self.mode.clear();
                self.mode.push(val);
                self.mode_count = *entry;
            } else if *entry == self.mode_count {
                self.mode.push(val);
            }
        }
    }
}

