pub trait SliceOfArrayExt {
    type T;
    fn flatten_ext(&self) -> &[Self::T];
    fn flatten_mut_ext(&mut self) -> &mut [Self::T];
}

impl<T, const N: usize> SliceOfArrayExt for [[T; N]] {
    type T = T;
    fn flatten_ext(&self) -> &[Self::T] {
        flatten(self)
    }
    fn flatten_mut_ext(&mut self) -> &mut [Self::T] {
        flatten_mut(self)
    }
}

pub const fn flatten<T, const N: usize>(vals: &[[T; N]]) -> &[T] {
    let len = if core::mem::size_of::<T>() == 0 {
        match vals.len().checked_mul(N) {
            Some(v) => v,
            None => panic!("slice len overflow"),
        }
    } else {
        vals.len() * N
    };
    unsafe { core::slice::from_raw_parts(vals.as_ptr().cast(), len) }
}

pub fn flatten_mut<T, const N: usize>(vals: &mut [[T; N]]) -> &mut [T] {
    let len = if core::mem::size_of::<T>() == 0 {
        vals.len().checked_mul(N).expect("slice len overflow")
    } else {
        vals.len() * N
    };
    unsafe { core::slice::from_raw_parts_mut(vals.as_mut_ptr().cast(), len) }
}

use std::convert::Infallible;

pub struct Bits {
    pub data: u16,
    pub len: u8,
}

pub enum Color {
    Black,
    White,
}

pub trait BitWriter {
    type Error;
    fn write(&mut self, bits: Bits) -> Result<(), Self::Error>;
    fn pad(&mut self);
}

pub struct VecWriter {
    data: Vec<u8>,
    partial: u32,
    len: u8,
}

impl BitWriter for VecWriter {
    type Error = Infallible;
    fn write(&mut self, bits: Bits) -> Result<(), Self::Error> {
        self.partial |= (bits.data as u32) << (32 - self.len - bits.len);
        self.len += bits.len;
        while self.len >= 8 {
            self.data.push((self.partial >> 24) as u8);
            self.partial <<= 8;
            self.len -= 8;
        }
        Ok(())
    }
    fn pad(&mut self) {
        if self.len > 0 {
            self.data.push((self.partial >> 24) as u8);
            self.partial = 0;
            self.len = 0;
        }
    }
}

impl VecWriter {
    pub fn new() -> Self {
        VecWriter { data: Vec::new(), partial: 0, len: 0 }
    }
}

