pub trait MapProblemOr {
    type ProblemCarrier;
    fn map_problem_or(self, problem: impl Into<Problem>) -> Self::ProblemCarrier;
    fn map_problem_or_else<F, P>(self, problem: F) -> Self::ProblemCarrier where F: FnOnce() -> P, P: Into<Problem>;
}

impl<O, E> MapProblemOr for Result<O, Option<E>> where E: Into<Problem> {
    type ProblemCarrier = Result<O, Problem>;
    fn map_problem_or(self, problem: impl Into<Problem>) -> Result<O, Problem> {
        self.map_err(|e| e.map(Into::into).unwrap_or_else(|| problem.into()))
    }
    fn map_problem_or_else<F, P>(self, problem: F) -> Result<O, Problem> where F: FnOnce() -> P, P: Into<Problem> {
        self.map_err(|e| e.map(Into::into).unwrap_or_else(|| problem().into()))
    }
}

