use reqwest::{Client as HttpClient, Url};

pub struct Client {
    host: Url,
    db: String,
    authentication: Option<(String, String)>,
    jwt_token: Option<String>,
    client: HttpClient,
}

impl Client {
    pub fn default() -> Self {
        Client::new(Url::parse("http://localhost:8086").unwrap(), "test")
    }
    pub fn new<T>(host: Url, db: T) -> Self
    where
        T: Into<String>,
    {
        Client {
            host,
            db: db.into(),
            authentication: None,
            jwt_token: None,
            client: HttpClient::default(),
        }
    }
    pub fn set_authentication<T>(mut self, user: T, passwd: T) -> Self
    where
        T: Into<String>,
    {
        self.authentication = Some((user.into(), passwd.into()));
        self
    }
    pub fn switch_database<T>(&mut self, database: T)
    where
        T: Into<String>,
    {
        self.db = database.into();
    }
}

use std::net::SocketAddr;

pub struct UdpClient {
    hosts: Vec<SocketAddr>,
}

impl UdpClient {
    pub fn new(address: SocketAddr) -> Self {
        UdpClient { hosts: vec![address] }
    }
    pub fn add_host(&mut self, address: SocketAddr) {
        self.hosts.push(address);
    }
}

#[macro_export]
macro_rules! cta_type_same_size {
    ( $Type1:ty, $Type2:ty $(,)? ) => {{
        const _ : fn() = || {
            let _ : [ () ; core::mem::size_of::< $Type1 >() ] = [ () ; core::mem::size_of::< $Type2 >() ];
        };
        true
    }}
}

